from typing import List

def missing_number(nums: List[int]) -> int:
    n = len(nums)
    expected = n * (n + 1) // 2
    return expected - sum(nums)

function missingNumber(nums) {
    const n = nums.length;
    const expected = n * (n + 1) / 2;
    return expected - nums.reduce((a, b) => a + b, 0);
}
